mapper.select:
select count(*)
from `order`
join dept on `order`.dept_id = dept.id


        and `order`.no like concat(#{no},'%')


        and `order`.type = #{type}


        and dept.name like concat('%',#{dept},'%')


        and `order`.state = #{state}


        and `order`.eat_mode = #{eatMode}


        and `order`.dept_id in

            #{deptId}

select `order`.id, `order`.type, `order`.state, `order`.eat_mode, `order`.dept_id, dept.name as deptName,
       `order`.pay_money as finish_price,`order`.expiration_time, `order`.create_time
from `order`
join dept on `order`.dept_id = dept.id


        and `order`.no like concat(#{no},'%')


        and `order`.type = #{type}


        and dept.name like concat('%',#{dept},'%')


        and `order`.state = #{state}


        and `order`.eat_mode = #{eatMode}


        and `order`.dept_id in

            #{deptId}



limit #{skip},#{pageSize}

select count(*)
from `order`
left join dept on `order`.dept_id = dept.id

    `order`.client_id = #{loginUserId} and `order`.client_type = 1

        and `order`.no like concat(#{no},'%')


        and `order`.type = #{type}


        and dept.name like concat('%',#{dept},'%')


        and `order`.state = #{state}


        and `order`.eat_mode = #{eatMode}

select `order`.id, `order`.type, `order`.state, `order`.eat_mode, `order`.dept_id, dept.name as deptName,
`order`.pay_money as finish_price,`order`.expiration_time, `order`.create_time
from `order`
left join dept on `order`.dept_id = dept.id

    `order`.client_id = #{loginUserId} and `order`.client_type = 1

        and `order`.no like concat(#{no},'%')


        and `order`.type = #{type}


        and dept.name like concat('%',#{dept},'%')


        and `order`.state = #{state}


        and `order`.eat_mode = #{eatMode}


limit #{skip},#{pageSize}

select o.client_id,oc.coupon_id,count(*) as num
from `order` o join order_coupon oc on o.id = oc.order_id
where oc.order_id in

    #{orderId}

group by o.client_id,oc.coupon_id;
